import logo from "./logo.svg";
import "./App.css";
import { useState } from "react";
function App() {
    return (
        <div className="App">
            <Parent />
        </div>
    );
}
const Parent = function () {
    const [count, setCount] = useState(0);
    const date = new Date("mar 3 2026");
    return (
        <>
            <Steps count={count} setCount={setCount} />
            <Counter count={count} setCount={setCount} />
            <p>{count === 0 ? "Today is" : count > 0 ? `${count} days from today is` : `${count} days ago was `}</p>
        </>
    );
};
const Steps = function ({ count, setCount }) {
    const countPlus = function () {
        setCount(count + 1);
    };
    const countMinus = function () {
        setCount(count - 1);
    };
    return (
        <div className="counter-steps">
            <button type="button" onClick={countMinus}>
                -
            </button>
            <span>Step:{count}</span>
            <button type="button" onClick={countPlus}>
                +
            </button>
        </div>
    );
};
const Counter = function ({ count, setCount }) {
    const countPlus = function () {
        setCount(count + 1);
    };
    const countMinus = function () {
        setCount(count - 1);
    };
    return (
        <div className="counter-steps">
            <button type="button" onClick={countMinus}>
                -
            </button>
            <span>Count:{count}</span>
            <button type="button" onClick={countPlus}>
                +
            </button>
        </div>
    );
};
export default App;
